// ============================================
// Game Loop (simple tick-based simulation)
// ============================================

class GameLoop {
  constructor(gameServer) {
    this.server = gameServer;
    this.tickRate = 100; // ms per tick
    this.interval = null;
  }

  start() {
    this.interval = setInterval(() => this.tick(), this.tickRate);
    console.log(`Game loop started at ${1000 / this.tickRate} ticks/second`);
  }

  stop() {
    if (this.interval) {
      clearInterval(this.interval);
      this.interval = null;
    }
  }

  tick() {
    const dt = this.tickRate / 1000;

    // Update unit positions
    for (const unit of this.server.gameState.units.values()) {
      if (unit.status === 'moving' && unit.destination) {
        const dx = unit.destination.x - unit.position.x;
        const dy = unit.destination.y - unit.position.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        if (dist < unit.speed * dt) {
          unit.position.x = unit.destination.x;
          unit.position.y = unit.destination.y;
          unit.destination = null;
          unit.status = 'idle';
        } else {
          unit.position.x += (dx / dist) * unit.speed * dt;
          unit.position.y += (dy / dist) * unit.speed * dt;
        }
      }

      // Handle gathering
      if (unit.status === 'gathering' && unit.targetId) {
        const resource = this.server.gameState.resources.get(unit.targetId);
        if (resource && resource.amount > 0) {
          const dist = this.server.calculateDistance(unit.position, resource.position);
          if (dist < 2) {
            const gatherAmount = Math.min(5, resource.amount);
            resource.amount -= gatherAmount;
            const player = this.server.findPlayerById(unit.ownerId);
            if (player) {
              const resourceType = resource.type === 'gold_mine' ? 'gold' :
                resource.type === 'forest' ? 'wood' : 'food';
              player.resources[resourceType] += gatherAmount;
            }
          } else {
            // Move toward resource
            const dx = resource.position.x - unit.position.x;
            const dy = resource.position.y - unit.position.y;
            unit.position.x += (dx / dist) * unit.speed * dt;
            unit.position.y += (dy / dist) * unit.speed * dt;
          }
        } else {
          unit.status = 'idle';
          unit.targetId = null;
        }
      }
    }
  }
}

// ============================================
// Start Server
// ============================================

const server = new GameServer(8080);
const gameLoop = new GameLoop(server);
gameLoop.start();

// Graceful shutdown
process.on('SIGINT', () => {
  console.log('\nShutting down...');
  gameLoop.stop();
  server.shutdown();
  process.exit(0);
});

